    // synchronous single-port read mapped to a BRAM tile.
    (* rom_style = "block", ram_style = "block" *) reg signed [31:0] biases_l0 [0:OC-1];
    (* rom_style = "block", ram_style = "block" *) reg signed [31:0] biases_l1 [0:OC-1];
    (* rom_style = "block", ram_style = "block" *) reg signed [31:0] biases_l2 [0:OC-1];
    (* rom_style = "block", ram_style = "block" *) reg signed [31:0] biases_l3 [0:OC-1];

