    wire [BIAS_ADDR_W-1:0] bias_addr2 = oc_group * MP + 2;
    wire [BIAS_ADDR_W-1:0] bias_addr3 = oc_group * MP + 3;

    reg signed [31:0] bias_q0, bias_q1, bias_q2, bias_q3;

