    reg [$clog2(MP+1)-1:0]        lane_counter;
    reg [$clog2(OC_PASSES+1)-1:0] oc_group;
    reg [$clog2(IN_BEATS+1)-1:0]  in_beat;
    reg [$clog2(OUT_BEATS+1)-1:0] out_beat;
    reg [2:0] state;

