            ready_in         <= 1'b1;  // [INVARIANT:READY_IN_GATING]
            valid_out        <= 1'b0;
            in_beat          <= 0;
            out_beat         <= 0;
            k_counter        <= 0;
            lane_counter     <= 0;
            oc_group         <= 0;
