            mac_valid_q2     <= mac_valid_q1;
            mac_lane_q2      <= mac_lane_q1;
            mac_global_oc_q2 <= mac_global_oc_q1;

            if (mac_valid_q2 && mac_global_oc_q2 < OC) begin
                acc[mac_lane_q2] <= acc[mac_lane_q2] + $signed(mul_q);
            end

            case (state)

            ST_INPUT: begin
                valid_out    <= 1'b0;
                mac_valid_q1 <= 1'b0;
                mac_valid_q2 <= 1'b0;
                if (valid_in) begin
                    for (ch = 0; ch < CHANNEL_TILE; ch = ch + 1) begin
                        in_latch[in_beat * CHANNEL_TILE + ch] <=
                            $signed(data_in[ch*8 +: 8]);
                    end
                    if (in_beat == IN_BEATS - 1) begin
                        in_beat          <= 0;
                        ready_in         <= 1'b0;  // [INVARIANT:READY_IN_GATING]
                        k_counter        <= 0;
                        lane_counter     <= 0;
                        oc_group         <= 0;
                        mac_done_issuing <= 1'b0;
                        for (lane = 0; lane < MP; lane = lane + 1)
                            acc[lane] <= 0;
                        state            <= ST_RUNNING;
                    end else begin
                        in_beat <= in_beat + 1;
                    end
                end
