                    oc_group     <= oc_group + 1;
                    k_counter    <= 0;
                    lane_counter <= 0;
                    for (lane = 0; lane < MP; lane = lane + 1)
                        acc[lane] <= 0;
                    state        <= ST_RUNNING;
                end
            end

            ST_STREAM_OUT: begin
                if (out_beat == OUT_BEATS - 1) begin
                    valid_out <= 1'b0;
                    ready_in  <= 1'b1;  // [INVARIANT:READY_IN_GATING]
