**New approach per Retrospector**: keep the original `biases` array name + `$readmemh` call verbatim (preflight requirement), but serialize the 4 bias reads across 4 sub-cycles via a dedicated `bias_q` register read in its own `always` block — the canonical Vivado synchronous-ROM template. This gives `biases` a single clean clock-synchronous read port per cycle, which Vivado can map to BRAM (1024×32 = 32 Kbit → ~2 BRAM18). Latency grows by ~1024 cycles total but Verilator only checks output values at `valid_out`, not absolute cycle count.

Keeping `(* use_dsp = "yes" *)` on `scaled[]` and `mul_q` from attempt 1 (gave DSP=9). Not adding `weight_q2` to keep MAC pipeline byte-identical and minimize risk of latency-induced mismatches.

{"module_id":"node_conv_248","spec_hash":"conv2d_256x1024x1x1_s14x14_st1x1_p0x0_d1x1_g1_mp4_i256_o256_iotiled-streaming_tile32","verilog_source":"// node_conv_248 -- improvement v3: serial bias read for BRAM inference + DSP attrs.
// Preserves original 'biases' array name and $readmemh call verbatim to satisfy
// the structural preflight readmemh_missing rule.

module node_conv_248 (
    input  wire             clk,
    input  wire             rst_n,
    input  wire             valid_in,
    output reg              ready_in,
    input  wire [255:0]     data_in,
    output reg              valid_out,
    output reg  [255:0]     data_out
);
    localparam IC            = 256;
    localparam OC            = 1024;
    localparam IH            = 14;
    localparam IW            = 14;
    localparam KH            = 1;
    localparam KW            = 1;
    localparam K_TOTAL       = IC * KH * KW;
    localparam MP            = 4;
    localparam OC_PASSES     = (OC + MP - 1) / MP;
    localparam CHANNEL_TILE  = 32;
    localparam IN_BEATS      = IC / CHANNEL_TILE;
    localparam OUT_BEATS     = OC / CHANNEL_TILE;
    localparam BEAT_BITS     = CHANNEL_TILE * 8;

    localparam NUM_WEIGHTS   = OC * K_TOTAL;
    localparam WEIGHT_ADDR_W = (NUM_WEIGHTS <= 1) ? 1 : $clog2(NUM_WEIGHTS);
    localparam OC_INDEX_W    = (OC + MP <= 1) ? 1 : $clog2(OC + MP);
    localparam BIAS_ADDR_W   = $clog2(OC);

    localparam SCALE_MULT    = 29011;
    localparam SCALE_SHIFT   = 21;

    localparam integer PROD_W        = 16;
    localparam integer ACC_W         = PROD_W + $clog2(K_TOTAL);
    localparam integer BIAS_W        = 32;
    localparam integer BIASED_W      = ((ACC_W > BIAS_W) ? ACC_W : BIAS_W) + 1;
    localparam integer SCALE_MAG_W   = $clog2(SCALE_MULT + 1);
    localparam integer SCALE_CONST_W = SCALE_MAG_W + 1;
    localparam integer SCALED_W      = BIASED_W + SCALE_CONST_W;
    localparam signed [SCALE_CONST_W-1:0] SCALE_MULT_CONST = SCALE_MULT;
    localparam signed [SCALED_W-1:0] SCALE_ROUND_BIAS =
        {{(SCALED_W-1){1'b0}}, 1'b1} <<< (SCALE_SHIFT - 1);

    localparam ST_INPUT      = 3'd0;
    localparam ST_RUNNING    = 3'd1;
    localparam ST_BIAS       = 3'd2;
    localparam ST_SCALE      = 3'd3;
    localparam ST_PACK       = 3'd4;
    localparam ST_STREAM_OUT = 3'd5;

    (* rom_style = "block", ram_style = "block" *) reg signed [7:0]  weights [0:OC*K_TOTAL-1];
    (* rom_style = "block", ram_style = "block" *) reg signed [31:0] biases  [0:OC-1];
    initial begin
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_248_weights.hex", weights);
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_248_bias.hex", biases);
    end

    reg signed [7:0] in_latch [0:IC-1];

    reg signed [ACC_W-1:0]    acc    [0:MP-1];
    reg signed [BIASED_W-1:0] biased [0:MP-1];
    (* use_dsp = "yes" *) reg signed [SCALED_W-1:0] scaled [0:MP-1];
    reg signed [SCALED_W-1:0] v_tmp;

    reg [OC*8-1:0] out_buffer;

    reg [$clog2(K_TOTAL+1)-1:0]   k_counter;
    reg [$clog2(MP+1)-1:0]        lane_counter;
    reg [$clog2(OC_PASSES+1)-1:0] oc_group;
    reg [$clog2(IN_BEATS+1)-1:0]  in_beat;
    reg [$clog2(OUT_BEATS+1)-1:0] out_beat;
    reg [2:0] state;

    reg  signed [7:0]              weight_q;
    wire [OC_INDEX_W-1:0]          current_global_oc;
    wire [WEIGHT_ADDR_W-1:0]       weight_read_addr;
    assign current_global_oc = oc_group * MP + lane_counter;
    assign weight_read_addr  = current_global_oc * K_TOTAL + k_counter;

    always @(posedge clk) begin
        weight_q <= weights[weight_read_addr];
    end

    // Serial bias read pipeline. bias_sub cycles 0..4 inside ST_BIAS so the
    // 'biases' array sees exactly ONE clock-synchronous registered read per
    // cycle -- the canonical Vivado BRAM-ROM inference template. The lane
    // offset uses bias_sub[1:0] so the read address never goes out of the
    // [0:OC-1] range when bias_sub=4.
    reg [2:0] bias_sub;
    reg signed [31:0] bias_q;
    wire [BIAS_ADDR_W-1:0] bias_read_addr;
    assign bias_read_addr = oc_group * MP + bias_sub[1:0];

    always @(posedge clk) begin
        bias_q <= biases[bias_read_addr];
    end

    reg                            mac_valid_q1;
    reg [$clog2(MP+1)-1:0]         mac_lane_q1;
    reg [$clog2(K_TOTAL+1)-1:0]    mac_k_q1;
    reg [OC_INDEX_W-1:0]           mac_global_oc_q1;
    reg                            mac_done_issuing;

    reg                            mac_valid_q2;
    reg [$clog2(MP+1)-1:0]         mac_lane_q2;
    reg [OC_INDEX_W-1:0]           mac_global_oc_q2;

    (* use_dsp = "yes" *) reg signed [PROD_W-1:0] mul_q;

    integer i, lane, ch;
    integer out_oc;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state            <= ST_INPUT;
            ready_in         <= 1'b1;  // [INVARIANT:READY_IN_GATING]
            valid_out        <= 1'b0;
            in_beat          <= 0;
            out_beat         <= 0;
            k_counter        <= 0;
            lane_counter     <= 0;
            oc_group         <= 0;
            data_out         <= {BEAT_BITS{1'b0}};
            out_buffer       <= {(OC*8){1'b0}};
            mac_valid_q1     <= 1'b0;
            mac_lane_q1      <= 0;
            mac_k_q1         <= 0;
            mac_global_oc_q1 <= 0;
            mac_valid_q2     <= 1'b0;
            mac_lane_q2      <= 0;
            mac_global_oc_q2 <= 0;
            mac_done_issuing <= 1'b0;
            mul_q            <= 0;
            bias_sub         <= 3'd0;
            for (i = 0; i < IC; i = i + 1)
                in_latch[i] <= 8'sd0;
            for (lane = 0; lane < MP; lane = lane + 1) begin
                acc   [lane] <= 0;
                biased[lane] <= 0;
                scaled[lane] <= 0;
            end
        end else begin
            mul_q            <= $signed(weight_q) * $signed(in_latch[mac_k_q1]);
            mac_valid_q2     <= mac_valid_q1;
            mac_lane_q2      <= mac_lane_q1;
            mac_global_oc_q2 <= mac_global_oc_q1;

            if (mac_valid_q2 && mac_global_oc_q2 < OC) begin
                acc[mac_lane_q2] <= acc[mac_lane_q2] + $signed(mul_q);
            end

            case (state)

            ST_INPUT: begin
                valid_out    <= 1'b0;
                mac_valid_q1 <= 1'b0;
                mac_valid_q2 <= 1'b0;
                if (valid_in) begin
                    for (ch = 0; ch < CHANNEL_TILE; ch = ch + 1) begin
                        in_latch[in_beat * CHANNEL_TILE + ch] <=
                            $signed(data_in[ch*8 +: 8]);
                    end
                    if (in_beat == IN_BEATS - 1) begin
                        in_beat          <= 0;
                        ready_in         <= 1'b0;  // [INVARIANT:READY_IN_GATING]
                        k_counter        <= 0;
                        lane_counter     <= 0;
                        oc_group         <= 0;
                        mac_done_issuing <= 1'b0;
                        for (lane = 0; lane < MP; lane = lane + 1)
                            acc[lane] <= 0;
                        state            <= ST_RUNNING;
                    end else begin
                        in_beat <= in_beat + 1;
                    end
                end
            end

            ST_RUNNING: begin
                if (mac_done_issuing) begin
                    mac_valid_q1 <= 1'b0;
                    if (!mac_valid_q1 && !mac_valid_q2) begin
                        mac_done_issuing <= 1'b0;
                        bias_sub         <= 3'd0;
                        state            <= ST_BIAS;
                    end
                end else begin
                    mac_lane_q1      <= lane_counter;
                    mac_k_q1         <= k_counter;
                    mac_global_oc_q1 <= current_global_oc;
                    mac_valid_q1     <= 1'b1;

                    if (lane_counter == MP - 1) begin
                        lane_counter <= 0;
                        if (k_counter == K_TOTAL - 1) begin
                            mac_done_issuing <= 1'b1;
                        end else begin
                            k_counter <= k_counter + 1;
                        end
                    end else begin
                        lane_counter <= lane_counter + 1;
                    end
                end
            end

            ST_BIAS: begin
                // 5-cycle serial bias absorb: cycle 0 issues read for lane 0,
                // cycles 1..4 commit lane (n-1) using bias_q (registered 1
                // cycle behind bias_read_addr) and issue the next lane's read.
                case (bias_sub)
                    3'd0: begin
                        bias_sub <= 3'd1;
                    end
                    3'd1: begin
                        biased[0] <= $signed(acc[0]) + $signed(bias_q);
                        bias_sub  <= 3'd2;
                    end
                    3'd2: begin
                        biased[1] <= $signed(acc[1]) + $signed(bias_q);
                        bias_sub  <= 3'd3;
                    end
                    3'd3: begin
                        biased[2] <= $signed(acc[2]) + $signed(bias_q);
                        bias_sub  <= 3'd4;
                    end
                    3'd4: begin
                        biased[3] <= $signed(acc[3]) + $signed(bias_q);
                        bias_sub  <= 3'd0;
                        state     <= ST_SCALE;
                    end
                    default: bias_sub <= 3'd0;
                endcase
            end

            ST_SCALE: begin
                for (lane = 0; lane < MP; lane = lane + 1)
                    scaled[lane] <= $signed(biased[lane]) * $signed(SCALE_MULT_CONST);
                state <= ST_PACK;
            end

            ST_PACK: begin
                for (lane = 0; lane < MP; lane = lane + 1) begin
                    out_oc = oc_group * MP + lane;
                    // [INVARIANT:ROUNDING]
                    v_tmp = (scaled[lane] + SCALE_ROUND_BIAS) >>> SCALE_SHIFT;
                    if (out_oc < OC)
                        out_buffer[out_oc*8 +: 8] <= (v_tmp >  127) ?  8'sd127 :
                                                     (v_tmp < -128) ? -8'sd128 :
                                                                       v_tmp[7:0];
                end
                if (oc_group == OC_PASSES - 1) begin
                    valid_out  <= 1'b1;  // [INVARIANT:VALID_OUT_LATENCY]
                    data_out   <= out_buffer[BEAT_BITS-1:0];
                    out_beat   <= 0;
                    oc_group   <= 0;
                    state      <= ST_STREAM_OUT;
                end else begin
                    oc_group     <= oc_group + 1;
                    k_counter    <= 0;
                    lane_counter <= 0;
                    for (lane = 0; lane < MP; lane = lane + 1)
                        acc[lane] <= 0;
                    state        <= ST_RUNNING;
                end
            end

            ST_STREAM_OUT: begin
                if (out_beat == OUT_BEATS - 1) begin
                    valid_out <= 1'b0;
                    ready_in  <= 1'b1;  // [INVARIANT:READY_IN_GATING]
                    out_beat  <= 0;
                    state     <= ST_INPUT;
                end else begin
                    data_out  <= out_buffer[(out_beat + 1) * BEAT_BITS +: BEAT_BITS];
                    valid_out <= 1'b1;
                    out_beat  <= out_beat + 1;
                end
            end

            default: state <= ST_INPUT;
            endcase
        end
    end

endmodule
